-- 20260608_alchemy_neutral_tags_individual_recipes.sql
-- DNDNext Alchemy v8: neutral player-facing tags, Monster Parts catch-all,
-- individual resistance/immunity/bomb/oil recipes, and tag-filtered fourth slots.
--
-- Safe/idempotent:
--   * Creates every required recipe column before use.
--   * Updates existing catalog/plant/recipe rows by stable key or name.
--   * Inserts only rows that are missing.
--   * Leaves legacy recipe rows in place for rollback compatibility; the v8 UI hides them.
--
-- Player-facing model:
--   * Monster-derived ingredients display Family: Monster Parts.
--   * Neutral tags such as Fire, Cold, Psychic, Confusion, and Fear are visible.
--   * A recipe decides whether a matched tag creates resistance, immunity, damage, a bomb, or an oil.

BEGIN;

ALTER TABLE public.recipes
  ADD COLUMN IF NOT EXISTS alchemy_section text,
  ADD COLUMN IF NOT EXISTS alchemy_group text,
  ADD COLUMN IF NOT EXISTS template_key text,
  ADD COLUMN IF NOT EXISTS required_tags_any text[] NOT NULL DEFAULT '{}'::text[],
  ADD COLUMN IF NOT EXISTS tag_label text,
  ADD COLUMN IF NOT EXISTS base_duration_seconds integer,
  ADD COLUMN IF NOT EXISTS base_duration_dice_count integer,
  ADD COLUMN IF NOT EXISTS base_duration_die_size integer,
  ADD COLUMN IF NOT EXISTS base_duration_unit text,
  ADD COLUMN IF NOT EXISTS base_dice_count integer,
  ADD COLUMN IF NOT EXISTS base_die_size integer,
  ADD COLUMN IF NOT EXISTS base_flat_bonus integer,
  ADD COLUMN IF NOT EXISTS base_uses integer,
  ADD COLUMN IF NOT EXISTS dice_purpose text,
  ADD COLUMN IF NOT EXISTS effect_cadence text,
  ADD COLUMN IF NOT EXISTS condition_riders text[] NOT NULL DEFAULT '{}'::text[],
  ADD COLUMN IF NOT EXISTS cures_conditions text[] NOT NULL DEFAULT '{}'::text[],
  ADD COLUMN IF NOT EXISTS grants_immunities text[] NOT NULL DEFAULT '{}'::text[],
  ADD COLUMN IF NOT EXISTS formula_family text,
  ADD COLUMN IF NOT EXISTS theme_source text,
  ADD COLUMN IF NOT EXISTS rider_save text,
  ADD COLUMN IF NOT EXISTS rider_duration text,
  ADD COLUMN IF NOT EXISTS rider_repeat_save text;

COMMENT ON COLUMN public.recipes.required_tags_any IS
  'Neutral fourth-slot tags. At least one listed tag must match the selected ingredient.';
COMMENT ON COLUMN public.recipes.tag_label IS
  'Player-facing fourth-slot theme label, such as Fire, Confusion, or Blindness.';
COMMENT ON COLUMN public.recipes.alchemy_group IS
  'Player-facing recipe group inside Potions, Poisons, Bombs, Elixirs, or Oils.';
COMMENT ON COLUMN public.recipes.template_key IS
  'Shared internal rules template used by individually listed player-facing recipes.';

-- Canonical alchemy item catalog. This replaces v7 automatic rider metadata with
-- neutral brewTags while keeping stable item_key values for inventories and merchants.
