UPDATE public.items_catalog target
SET item_name = seed.item_name,
    item_type = seed.item_type,
    item_rarity = seed.item_rarity,
    price_gp = seed.price_gp,
    merchant_tags = COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.merchant_tags)), ARRAY[]::text[]),
    payload = seed.payload
FROM seed
WHERE target.item_key = seed.item_key;

