INSERT INTO public.items_catalog(item_key,item_name,item_type,item_rarity,price_gp,merchant_tags,payload)
SELECT seed.item_key,seed.item_name,seed.item_type,seed.item_rarity,seed.price_gp,
       COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.merchant_tags)), ARRAY[]::text[]),
       seed.payload
FROM seed
WHERE NOT EXISTS (
  SELECT 1 FROM public.items_catalog existing WHERE existing.item_key = seed.item_key
);

