UPDATE public.plants target
SET rarity = seed.rarity,
    category = seed.category,
    tags = COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.tags)), ARRAY[]::text[]),
    reagent_family = seed.reagent_family,
    family_label = seed.family_label,
    positive_effects = COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.positive_effects)), ARRAY[]::text[]),
    effect = seed.effect,
    alchemy_notes = seed.alchemy_notes,
    updated_at = now()
FROM seed
WHERE lower(target.name) = lower(seed.name);

