INSERT INTO public.plants(name,rarity,category,tags,reagent_family,family_label,positive_effects,effect,alchemy_notes)
SELECT seed.name,seed.rarity,seed.category,
       COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.tags)), ARRAY[]::text[]),
       seed.reagent_family,seed.family_label,
       COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.positive_effects)), ARRAY[]::text[]),
       seed.effect,seed.alchemy_notes
FROM seed
WHERE NOT EXISTS (
  SELECT 1 FROM public.plants existing WHERE lower(existing.name)=lower(seed.name)
);

