INSERT INTO public.recipes(
  name,description,recipe_type,discipline,rarity,base_dc,source,tags,duration,use_text,effect_text,
  formula_tags,required_tags,secondary_tags,enhancer_tags,output_quantity,batch_quantity,
  ingredients,ingredient_slots,family_formula,alchemy_section,alchemy_group,template_key,
  required_tags_any,tag_label,base_duration_seconds,base_duration_dice_count,base_duration_die_size,
  base_duration_unit,base_dice_count,base_die_size,base_flat_bonus,base_uses,dice_purpose,effect_cadence,
  condition_riders,cures_conditions,grants_immunities,formula_family,theme_source,rider_save,rider_duration,rider_repeat_save
)
SELECT
  seed.name,seed.description,seed.recipe_type,seed.discipline,seed.rarity,seed.base_dc,seed.source,
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.tags)), ARRAY[]::text[]),
  seed.duration,seed.use_text,seed.effect_text,
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.formula_tags)), ARRAY[]::text[]),
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.required_tags)), ARRAY[]::text[]),
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.secondary_tags)), ARRAY[]::text[]),
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.enhancer_tags)), ARRAY[]::text[]),
  seed.output_quantity,seed.batch_quantity,seed.ingredient_slots,seed.ingredient_slots,seed.family_formula,
  seed.alchemy_section,seed.alchemy_group,seed.template_key,
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.required_tags_any)), ARRAY[]::text[]),
  seed.tag_label,seed.base_duration_seconds,seed.base_duration_dice_count,seed.base_duration_die_size,
  seed.base_duration_unit,seed.base_dice_count,seed.base_die_size,seed.base_flat_bonus,seed.base_uses,
  seed.dice_purpose,seed.effect_cadence,
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.condition_riders)), ARRAY[]::text[]),
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.cures_conditions)), ARRAY[]::text[]),
  COALESCE(ARRAY(SELECT jsonb_array_elements_text(seed.grants_immunities)), ARRAY[]::text[]),
  seed.formula_family,seed.theme_source,seed.rider_save,seed.rider_duration,seed.rider_repeat_save
FROM seed
WHERE NOT EXISTS (
  SELECT 1 FROM public.recipes existing
  WHERE lower(existing.name)=lower(seed.name)
);

CREATE INDEX IF NOT EXISTS recipes_alchemy_section_group_idx
  ON public.recipes(alchemy_section,alchemy_group)
  WHERE alchemy_section IS NOT NULL;
CREATE INDEX IF NOT EXISTS recipes_template_key_idx
  ON public.recipes(template_key)
  WHERE template_key IS NOT NULL;
CREATE INDEX IF NOT EXISTS recipes_required_tags_any_gin_idx
  ON public.recipes USING gin(required_tags_any);
CREATE INDEX IF NOT EXISTS items_catalog_alchemy_brew_tags_gin_idx
  ON public.items_catalog USING gin((payload->'alchemy'->'brewTags'));

COMMIT;

